14‚Üí  const [shiftType, setShiftType] = useState('KUNDUZ');
15‚Üí  const [restingToday, setRestingToday] = useState([]);
16‚Üí
17‚Üí  const token = localStorage.getItem('token');
18‚Üí  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
