45‚Üí        setShowAddOp(false);
46‚Üí        fetchData();
47‚Üí        emitRefresh();
48‚Üí      } else {
49‚Üí        const data = await res.json();
50‚Üí        alert(data.detail || 'Xatolik yuz berdi');
51‚Üí      }
52‚Üí    } catch (e) { alert('Server xatoligi'); }
53‚Üí  };
54‚Üí
55‚Üí  const handleShiftChange = async (opId, newShift) => {
