136‚Üí              {restingToday.map(r => r.operator_name).join(', ')}
137‚Üí            </div>
138‚Üí          </div>
139‚Üí        </div>
140‚Üí      )}
141‚Üí
142‚Üí      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
143‚Üí        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Master Panel</h2>
144‚Üí        <div style={{ display: 'flex', gap: '8px' }}>
